import { Component, inject, OnInit } from '@angular/core';
import { AlertController, LoadingController, NavController } from '@ionic/angular';
import { AuthService } from '../auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.page.html',
  styleUrls: ['./login.page.scss'],
})
export class LoginPage implements OnInit {
  private loadingController = inject(LoadingController);
  private alertas = inject(AlertController);
  private navCtrl = inject(NavController); // Agrega el NavController para la navegación

  // Variables locales para capturar con ngModel
  email: string = "";
  password: string = "";
  color: string = 'primary'; // o el color que prefieras (e.g., 'secondary', 'danger', etc.)
  private authService = inject(AuthService);
  

  constructor() { }
  async validadInnicio() {
    try {
      await this.authService.login(this.email, this.password);
      this.navCtrl.navigateForward('/home');  // Navega a la página de inicio
    } catch (error) {
      console.error('Error de inicio de sesión:', error);
      // Puedes agregar una alerta o mensaje de error aquí
    }
  }

  async presentAlert() {
    const alert = await this.alertas.create({
      header: 'Error de inicio de sesión',
      message: 'Correo o contraseña incorrectos. Inténtalo nuevamente.',
      buttons: ['OK']
    });
    
    await alert.present();
  }

  async animacionLogin() {
    // Crea el loading con un mensaje
    const loading = await this.loadingController.create({
      message: 'Iniciando sesión...',
      duration: 3000 // Duración de la animación de carga: 3 segundos
    });

    await loading.present();
    await loading.onDidDismiss();

    // Navega a la página de perfil de estudiante después de la animación de carga
    this.navCtrl.navigateForward('/perfil-estudiante');
  }

 
  vistaPass() {
    this.navCtrl.navigateForward('/cambio-pass'); // Navega a la página de cambio de contraseña
  }

  ngOnInit() { }
}
<ion-content [fullscreen]="true">
  <ion-header>
    <ion-toolbar>
      <ion-buttons slot="start">
        <ion-back-button defaultHref="/home" color="success" icon-only="true"></ion-back-button>
      </ion-buttons>
      <ion-title color="success" class="ion-text-center">Login</ion-title>
    </ion-toolbar>
  </ion-header>

  <ion-content class="ion-padding center-content">
    <img src="https://i.pinimg.com/736x/3f/5a/d8/3f5ad816179850d23695910e906554a7.jpg" alt="Login" style="width: 100%; height: auto; margin-bottom: 20px;" />

    <ion-item>
      <ion-label color="success" position="floating">Correo</ion-label>
      <ion-input type="email" [(ngModel)]="email"></ion-input>
    </ion-item>
    
    <ion-item>
      <ion-label color="success" position="floating">Password</ion-label>
      <ion-input type="password" [(ngModel)]="password">
        <ion-input-password-toggle color="success" slot="end"></ion-input-password-toggle>
      </ion-input>
    </ion-item>

    <ion-button fill="outline" (click)="validadInnicio()" color="success" expand="block">
      Iniciar sesión
    </ion-button>
    <ion-button color="success" (click)="vistaPass()" fill="clear">
      ¿Cambiar contraseña?
    </ion-button>
  </ion-content>
</ion-content>
